import { getUrlProxyFromEnv } from '../utils/proxy-utils';
import { httpsAgent, httpsProxyAgent } from './https-agents';
import log from 'loglevel';

/**
 * If URL requires a proxy, returns a proxified httpsAgent that handles keep-alive.
 * This seems to be needed for corporate Renault proxy.
 *
 * If no proxy is needed, returns a regular httpsAgent.
 */

export function httpsAgentForURL(url: string) {
  let agent: any;

  const { msg, proxyUrl } = getUrlProxyFromEnv(url);
  const miniUrl = url.split('?').shift();

  if (proxyUrl) {
    agent = httpsProxyAgent;
    log.debug(`* Using ${proxyUrl} as a proxy for URL ${miniUrl} [${msg}]`);
  } else {
    agent = httpsAgent;
    log.debug(`* Not using a proxy for URL ${miniUrl} [${msg}]`);
  }

  return agent;
}
